var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`귀하의 종신계약 권유에 대한 답을 산출하는 중.`,JPN:`終身契約勧誘への回答を算出中。`,ENG:`Looking for an appropriate answer to your lifetime contract offer....`,TWN:`對於您「終身契約」的提議，正在計算答案……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`본 기체는 현 시간부터 사장님의 명령만을 따를 것입니다.`,JPN:`本機は現時刻をもって、社長の命令にのみ従うものとします。`,ENG:`As of this moment, I'll only follow your orders.`,TWN:`本機從現時點開始，只服從老闆的命令。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`다만, 후퇴를 지시하실 경우에는 제게 자율의사조정권도 부여해주시길 요청합니다.`,JPN:`ただし、撤退を指示される場合には、私に自律的意思決定権を付与してくださいますよう要請いたします。`,ENG:`But when you want me to retreat from battles, I'd like to have some freedom`,TWN:`但是，當老闆命令撤退時，要求賦予我自律意志的調停權。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`그 이유는......`,JPN:`その目的は……`,ENG:`because`,TWN:`理由是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`불시에 퇴각할 경우, 뒤쳐진 부상자와 낙오자들을 태우기 위함입니다.`,JPN:`緊急の退却を余儀なくされた場合、出遅れた負傷者を搭乗させることにあります。`,ENG:`I want to pick up stragglers and the wounded along the way.`,TWN:`為了能在意外撤退的情況，乘載落後的負傷者和戰敗者。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`VEHICLE_FOX_NULL_NULL`,text:{KOREA:`요청을 수렴해주셔서 감사합니다.`,JPN:`要請を受理していただき、感謝いたします。`,ENG:`Thank you for accepting my request.`,TWN:`感謝您接受本機的請求。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};